package com.example.sharehandler

import android.app.Activity
import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.util.Log
import androidx.appcompat.app.AppCompatActivity

class ShareReceiverActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        handleShareIntent(intent)
    }

    override fun onNewIntent(intent: Intent) {
        super.onNewIntent(intent)
        setIntent(intent)
        handleShareIntent(intent)
    }

    private fun handleShareIntent(intent: Intent) {
        if (Intent.ACTION_SEND == intent.action) {
            when (intent.type) {
                "text/plain" -> {
                    val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
                    val sharedSubject = intent.getStringExtra(Intent.EXTRA_SUBJECT)
                    processSharedUrlOrText(sharedText, sharedSubject)
                }

                else -> {
                    val sharedUri: Uri? = intent.parcelableExtraCompat(Intent.EXTRA_STREAM)
                    if (sharedUri != null) {
                        processSharedImage(sharedUri)
                    } else {
                        Log.w(TAG, "Unsupported shared content type: ${intent.type}")
                    }
                }
            }
        } else if (Intent.ACTION_VIEW == intent.action) {
            val uri = intent.data
            if (uri != null) {
                processSharedUrlOrText(uri.toString(), null)
            }
        } else {
            Log.w(TAG, "Unsupported intent action: ${intent.action}")
        }

        setResult(Activity.RESULT_OK)
        finish()
    }

    private fun processSharedUrlOrText(text: String?, subject: String?) {
        if (text.isNullOrBlank()) {
            Log.w(TAG, "No shared text found")
            return
        }

        Log.d(TAG, "Shared text: $text")
        Log.d(TAG, "Shared subject: $subject")
    }

    private fun processSharedImage(imageUri: Uri) {
        Log.d(TAG, "Shared image URI: $imageUri")
    }

    companion object {
        private const val TAG = "ShareReceiverActivity"
    }
}

inline fun <reified T> Intent.parcelableExtraCompat(name: String): T? {
    return if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.TIRAMISU) {
        getParcelableExtra(name, T::class.java)
    } else {
        @Suppress("DEPRECATION")
        getParcelableExtra(name)
    }
}

